<?php session_start(); require 'config/db.php'; require 'includes/functions.php';
$error=''; if($_SERVER['REQUEST_METHOD']==='POST'){ $email=$_POST['email']??''; $pass=$_POST['password']??''; $st=$pdo->prepare('SELECT u.*,r.name role FROM users u JOIN roles r ON r.id=u.role_id WHERE email=? AND status="active"'); $st->execute([$email]); $u=$st->fetch(); if($u && password_verify($pass,$u['password'])){ $_SESSION['user']=$u; log_action($pdo,'Login','User logged in'); header('Location:index.php'); exit; } else $error='Invalid login details'; }
?><!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>E-Stock Login</title><link rel="stylesheet" href="assets/css/style.css"></head><body><div class="login"><h1>E-Stock Login</h1><p>Secretariat of the Kondey Council</p><?php if($error) echo '<p class="low">'.e($error).'</p>'; ?><form method="post"><label>Email</label><input name="email" value="admin@kondeycouncil.gov.mv"><label>Password</label><input name="password" type="password" value="admin123"><button>Login</button></form><p class="small">Default: admin@kondeycouncil.gov.mv / admin123</p></div></body></html>
